''''''import os.pathimport refrom pathlib import Pathfrom typing import List, Optional, Dictimport SimpleITK as sitkdef natural_sort_key(filename: str) -> List[int]:    """    生成自然排序的键值，正确处理带数字的文件名（如1-001.dcm < 1-010.dcm）    Args:        filename: 待排序的文件名    Returns:        提取出的数字列表，用于排序比较    """    return [int(num) for num in re.findall(r"\d+", filename)]def read_dicom_series_professional(        dicom_dir: Path,        use_filename_order: bool = True,        file_suffix: str = ".dcm") -> sitk.Image:    """    专业级DICOM序列读取器，自动处理物理空间不一致问题    这是医学影像处理的标准方法，完全避免JoinSeries错误    Args:        dicom_dir: DICOM文件夹路径        use_filename_order: 是否使用文件名自然排序        file_suffix: DICOM文件后缀    Returns:        正确的3D SimpleITK图像（包含完整正确的物理空间信息）    """    # 验证输入路径    if not dicom_dir.is_dir():        raise NotADirectoryError(f"输入路径不是有效的文件夹: {dicom_dir}")    # 获取所有DICOM文件    dicom_files: List[Path] = list(dicom_dir.glob(f"*{file_suffix}"))    if not dicom_files:        raise FileNotFoundError(f"在文件夹中没有找到后缀为{file_suffix}的文件: {dicom_dir}")    # 排序文件    if use_filename_order:        # 按你的1-001.dcm格式自然排序        dicom_files.sort(key=lambda x: natural_sort_key(x.name))        # 转换为字符串路径列表        file_paths: List[str] = [str(f) for f in dicom_files]    else:        # 让SimpleITK自动根据DICOM元数据排序（最标准）        series_ids: List[str] = sitk.ImageSeriesReader.GetGDCMSeriesIDs(str(dicom_dir))        if not series_ids:            raise RuntimeError("在文件夹中没有找到有效的DICOM序列")        file_paths = sitk.ImageSeriesReader.GetGDCMSeriesFileNames(str(dicom_dir), series_ids[0])    print(file_paths)    # 创建专业的序列读取器    reader: sitk.ImageSeriesReader = sitk.ImageSeriesReader()    reader.SetFileNames(file_paths)    try:        # 一次性读取整个序列，自动计算正确的3D物理空间        volume: sitk.Image = reader.Execute()        return volume    except Exception as e:        raise RuntimeError(f"读取DICOM序列失败\n错误: {str(e)}") from edef save_as_nifti(        image: sitk.Image,        output_path: Path) -> None:    """    将SimpleITK图像保存为**轻微压缩**的NIfTI(.nii.gz)格式    使用压缩级别1：速度最快，压缩率最低（只压缩一点点）    Args:        image: 要保存的SimpleITK图像        output_path: 输出文件路径（建议以.nii.gz结尾）    Raises:        RuntimeError: 保存图像失败    """    # 确保输出目录存在    output_path.parent.mkdir(parents=True, exist_ok=True)    # 配置写入器：轻微压缩（级别1）    writer: sitk.ImageFileWriter = sitk.ImageFileWriter()    writer.SetFileName(str(output_path))    writer.SetUseCompression(True)    writer.SetCompressionLevel(1)  # 核心修改：最低压缩率，最快速度    try:        writer.Execute(image)    except Exception as e:        raise RuntimeError(f"保存NIfTI文件失败: {output_path}\n错误: {str(e)}") from edef dcm_to_nii(        input_dir: str | Path,        output_file: Optional[str | Path] = None,        use_filename_order: bool = True,idx = None) -> Path:    """    将文件夹中的DICOM序列转换为单个**轻微压缩**的NIfTI(.nii.gz)文件    Args:        input_dir: 输入DICOM文件夹路径        output_file: 输出NIfTI文件路径（默认：输入文件夹名.nii.gz）        use_filename_order: 是否使用文件名自然排序    Returns:        生成的NIfTI文件的完整路径    """    input_path: Path = Path(input_dir).resolve()   # 转换为绝对路径    rawname  = input_path.name    if idx is None:        name = "LIDC_IDRI_NA_"+rawname.split("-")[2]+".nii.gz"    else:        name = "LIDC_IDRI_"+idx+"_NA_" + rawname.split("-")[2] + ".nii.gz"    # 生成默认输出路径（输入文件夹同级目录 ）    output_path = Path(output_file+name).resolve()    # 执行转换   读取    volume: sitk.Image =read_dicom_series_professional(        dicom_dir=input_path,        use_filename_order=use_filename_order    )    save_as_nifti(        image=volume,        output_path=output_path    )    print(f"✅ 转换成功（轻微压缩，级别1）！")    print(f"输入文件夹: {input_path}")    print(f"输出文件: {output_path}")    print(f"图像尺寸: {volume.GetSize()}")    print(f"体素间距: {volume.GetSpacing()}")    print(f"图像原点: {volume.GetOrigin()}")    return output_pathif __name__ == "__main__":    # ==============================================    # 在这里修改你的配置（唯一需要修改的地方）    # ==============================================    # INPUT_DICOM_DIR = r"E:\project\Dataset\manifest-1600709154662\LIDC-IDRI\LIDC-IDRI-0001\01-01-2000-NA-NA-30178\3000566.000000-NA-03192"  # DICOM文件夹路径    # OUTPUT_NII_FILE = r"E:\project\Dataset\manifest-1600709154662\nii\\"  # 输出文件路径，None表示自动生成（文件夹名.nii.gz）    # USE_FILENAME_ORDER = True  # True=按1-001.dcm排序，False=按DICOM InstanceNumber    # # ==============================================    # # 在这里修改你的配置    # # ==============================================    #    # try:    #     dcm_to_nii(    #         input_dir=INPUT_DICOM_DIR,    #         output_file=OUTPUT_NII_FILE,    #         use_filename_order=USE_FILENAME_ORDER    #     )    # except Exception as e:    #     print(f"❌ 转换失败: {str(e)}")    #     exit(1)    #多文件夹处理   用于将，dcm 转换为 nii    root_path  =  r"E:\project\Dataset\manifest-1600709154662\LIDC2"    save_path = r"E:\project\Dataset\manifest-1600709154662\nii\\"    list_dir = os.listdir(root_path)    for sub_dir in list_dir:        path_sub_dir = os.path.join(root_path, sub_dir)   # r"E:\project\Dataset\manifest-1600709154662\LIDC-IDRI\LIDC-IDRI-0081"        if os.path.isfile(path_sub_dir):            continue        print(path_sub_dir)        _,name  = os.path.split(path_sub_dir)        idx = name.split("-")[2]        print(f"start dcm 2nii : {idx}")        #  进入第二层子文件夹        second_path_dir = os.listdir(path_sub_dir)        for second_sub_dir in second_path_dir:            path_second_sub_dir = os.path.join(path_sub_dir, second_sub_dir)   # r"E:\project\Dataset\manifest-1600709154662\LIDC-IDRI\LIDC-IDRI-0081\01-01-2000-NA-NA-30178"            # 进入第三层子文件夹            print(path_second_sub_dir)            third_path_dir = os.listdir(path_second_sub_dir )            for third_sub_dir in third_path_dir:                path_third_sub_dir = os.path.join(path_second_sub_dir, third_sub_dir)   #  E:\project\Dataset\manifest-1600709154662\LIDC-IDRI\LIDC-IDRI-0081\01-01-2000-NA-NA-30178\3001613.000000-NA-05796                # 判断文件数量                print(path_third_sub_dir)                if len(os.listdir(path_third_sub_dir)) < 10:                    print(path_third_sub_dir," No enghoh file ")                    continue                dcm_to_nii(path_third_sub_dir, save_path, use_filename_order=True,idx=idx)                print(path_third_sub_dir," Done")